+    state->count = 0;
+    state->threshold = threshold;
+    state->ok_count = 0;
+    state->fail_count = 0;
+    state->decided = 0;
+    state->draining = 0;
+    state->drained = 0;
+    for (i = 0; i < ASX_COMBINATOR_MAX_BRANCHES; i++) branch_init(&state->branches[i]);
