+static asx_status st_sink_;
+#define MUST_OK(expr)                                                                              \
+    do {                                                                                           \
+        st_sink_ = (expr);                                                                         \
+        (void)st_sink_;                                                                            \
+    } while (0)
+
+static asx_runtime g_rt;
+static void setup_runtime(void) { MUST_OK(asx_runtime_init_default(&g_rt)); }
+static void teardown_runtime(void) { asx_runtime_reset(); }
