+TEST(join_two_immediate) {
+    asx_join_state js;
+    MUST_OK(asx_join_init(&js));
+    MUST_OK(asx_join_add(&js, poll_ok, NULL));
+    MUST_OK(asx_join_add(&js, poll_ok, NULL));
