+    MUST_OK(asx_join_add(&js, poll_fail, &fail_st));
+    ASSERT_EQ(asx_join_poll(&js, 0), ASX_OK); /* completes (all done) */
+    /* Combined outcome reflects the failure */
+    ASSERT_EQ(asx_join_outcome(&js).severity, ASX_OUTCOME_ERR);
