+    ASSERT_TRUE(bracket_use_called);
+    ASSERT_TRUE(bracket_release_called);
+}
+
+TEST(bracket_use_fails_release_still_called) {
+    asx_bracket_state bs;
+    bracket_acquire_called = 0;
+    bracket_use_called = 0;
+    bracket_release_called = 0;
