+    ASSERT_FALSE(asx_symbol_set_contains(&s, 10));
+    ASSERT_TRUE(asx_symbol_set_contains(&s, 20));
+    ASSERT_EQ(asx_symbol_set_count(&s), (uint16_t)1);
